INSERT INTO tanahpedia_entry (id, unique_name, title, content, created_at, updated_at) VALUES
	('ea300000-0000-4000-8000-000000000001', 'tanahpedia-lab-01-two-bio-parents', 'מעבדה 01 — אב ואם ביולוגיים', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000002', 'tanahpedia-lab-02-father-only', 'מעבדה 02 — אב ביולוגי בלבד', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000003', 'tanahpedia-lab-03-mother-only', 'מעבדה 03 — אם ביולוגית בלבד', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000004', 'tanahpedia-lab-04-alt-two-fathers', 'מעבדה 04 — שני אבות בחלופי (alt_group)', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000005', 'tanahpedia-lab-05-stepfather-bio-mother', 'מעבדה 05 — אב חורג + אם ביולוגית', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000006', 'tanahpedia-lab-06-adoptive-mother', 'מעבדה 06 — אם מאימוץ + אב ביולוגי', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000007', 'tanahpedia-lab-07-foster-father', 'מעבדה 07 — אב אומנה (FOSTER)', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
	('ea300000-0000-4000-8000-000000000008', 'tanahpedia-lab-08-one-marriage', 'מעבדה 08 — בת זוג אחת (נישואין)', '<p>דמו מעבדת מקרי קצה — לא לעריכה פומבית.</p>', NOW(), NOW()),
